<template>
    <div>
        <div class="container-fluid p-l-0 p-r-0">
            <div class="page-header">
                <div class="row">
                    <div class="col-sm-6">
                        <h6><span>Registros de actividades</span></h6>
                        <ol class="breadcrumb">
                            <li class="breadcrumb-item">
                                <a href="/dashboard">Registros</a>
                            </li>
                            <li class="breadcrumb-item active">
                                <span class="text-muted">Actividades</span>
                            </li>
                        </ol>
                    </div>
                    <div class="col-sm-6 d-flex justify-content-end">
                        <div class="bookmark">
                           
                                    <el-tooltip
                                        class="item"
                                        effect="dark"
                                        content="Operaciones"
                                        placement="bottom-end"
                                    >
                                        <a
                                            class="btn btn-primary btn-icon btn-icon-start"
                                        >
                                           Ver en tiempo real
                                        </a>
                                    </el-tooltip>
                        </div>
                        <!-- Bookmark Ends-->
                    </div>
                </div>
            </div>
        </div>
        <!-- Container-fluid starts-->
        <div class="container-fluid p-l-0 p-r-0">
            <div class="card mb-0">
             
                <div class="card-body">
                    <table class="table table-responsive">
                        <thead>
                            <tr>
                                <th>Fecha</th>
                                <th>Usuario</th>
                                <th>Descripción</th>
                                <th>Detalle</th>
                                <th>Registro</th>
                            </tr>
                        </thead>

                        <tbody class="registers_event">
                            <tr v-for="(record, index) in records" :key="index"
                        
                            :class="record.event == 'create' ? 'bg-success': (record.event == 'update' ? 'bg-primary' : 'bg-danger')"
                             >
                                <td>
                                    <h6 class="text-white">{{record.time_of_issue}}</h6>
                                    <h5 class="text-white">{{record.date_of_issue}}</h5>

                                </td>
                                <td> {{record.user}}</td>
                                <td>
                                    {{record.description}}
                                </td>
                                 <td>
                                    <div class="flex flex-wrap ">
                                        <span class="m-2" v-for="(detail,key) in record.detail" :key="key">
                                                    <strong>{{translatePros[key]}}</strong> :{{detail}}
                                                    
                                        </span>
                                    </div>
                                </td>
                                <td>
                                    {{record.event_description}}
                                </td>
                               
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    </div>
</template>
<style>
.registers_event td{
    color: #fff !important;
}
</style>
<script>
import { deletable } from "../../mixins/deletable";

export default {
    props: [ "configuration", "user_type"],
    mixins: [deletable],
    components: {
        
    },
    data() {
        return {
            loading: false,
            records:[],
            resource: "registers",
            translatePros:{
                "number": "Número",
                "table": "Mesa",
                "area": "Área",
                "customer": "Cliente",
                "ref": "Referencia",
                "total": "Total",
                "food": "Pedido",
                "quantity": "Cantidad",
                "price": "Precio",
                "observations": "Observaciones",
                "method": "Método de pago",
                "document": "Documento",
                "amount": "Monto",
                "description": "Descripción",
            },
          
        };
    },
    created() {
        this.getRecords();
        console.log(this.configuration);
    },
    filters: {},
    methods: {

        async getRecords(){
            try{
                this.loading = true;
                const response = await this.$http.get(`/${this.resource}/records`);
                if(response.status === 200){
                    this.records = response.data.data;
                }
            }catch(e){
                console.log(e);
            }finally{
                this.loading = false;
            }
        }
    },
    mounted() {}
};
</script>



